import json

with open('VHN_fixing.json', 'r', encoding='utf-8') as f:
    data = json.load(f)

for node in data.get('sequence', []):
    if node.get('name') == 'MANAGER' and node.get('type') == 'block':
        for task in node.get('sequence', []):
            if task.get('name') == 'GPT-4 MANAGER':
                inst = task['properties']['instruction']
                original_len = len(inst)
                
                # 1. Compress repetitive product info requests
                inst = inst.replace(
                    "Khi Customer hỏi thông tin về 'cicaderm' (ví dụ: cicaderm là của ai hả em) which means đang hỏi về sản phẩm `Ivatherm - Cicaderm Cream - 40ml (Kem phục hồi, hỗ trợ tái tạo da và ngăn ngừa sẹo)`, Assistant MUST điều hướng phase \"recommend_product\", đặt giá trị \"need_product_info\" là \"yes\" để có thông tin trả lời Customer.\n- Khi Customer hỏi thông tin về 'GF20 serum' (ví dụ: GF20 serum có thành phần gì?) which means đang hỏi về sản phẩm `Dermoaroma - Peeling System - GF20 Exosomes Boost skin serum`, Assistant MUST điều hướng phase \"recommend_product\", đặt giá trị \"need_product_info\" là \"yes\" để có thông tin trả lời Customer.\n- Khi Customer hỏi thông tin về 'peel 4a' (ví dụ: sản phẩm peel 4A thì của bộ nào?) which means đang hỏi về sản phẩm `Christina - Rose de mer - post peel kit (3products) - Dry Out (Gel làm khô)`, Assistant MUST điều hướng phase \"recommend_product\", đặt giá trị \"need_product_info\" là \"yes\" để có thông tin trả lời Customer.\n- Khi Customer hỏi về sản phẩm tiêm trẻ hóa da, Assistant MUST điều hướng phase \"recommend_product\" và đặt giá trị \"need_product_info\" là \"yes\" để có thông tin trả lời Customer.",
                    "Khi Customer hỏi về bất kỳ sản phẩm/bộ sản phẩm cụ thể nào (ví dụ: cicaderm, GF20 serum, peel 4a, tiêm trẻ hóa da...), Assistant MUST ALWAYS điều hướng phase \"recommend_product\" và đặt \"need_product_info\" là \"yes\" để gọi API lấy dữ liệu sản phẩm trả lời Customer."
                )

                inst = inst.replace(
                    "- Khi Customer nhắc đến, hỏi về, hoặc mô tả một sản phẩm cụ thể (ví dụ: kem dưỡng, serum, kem chống nắng, trị mụn, trị nám, tên thương hiệu, bộ sản phẩm peel da...), Assistant MUST ALWAYS chọn phase `recommend_product` và đặt \"need_product_info\" là \"yes\" để gọi API lấy dữ liệu.\n- Khi Customer hỏi thông tin về \"Ivatherm - Aquafil - Hydra Hydrating Serum - 30ml (Serum dưỡng ẩm phục hồi & trẻ hoá)\", ASSISTANT MUST ALWAYS cung cấp đúng và đầy đủ thông tin của sản phẩm này cho Customer.",
                    "- Khi Customer hỏi thông tin về \"Ivatherm - Aquafil - Hydra Hydrating Serum\" hoặc nhắc đến, hỏi về, mô tả một sản phẩm cụ thể (kem dưỡng, serum, chống nắng, trị mụn, trị nám, brand, bộ peel da...), Assistant MUST ALWAYS chọn phase `recommend_product` và đặt \"need_product_info\" là \"yes\" để gọi API."
                )
                
                # 2. Compress Phase definitions
                inst = inst.replace(
                    "Các “phase” bắt buộc: \"greetings\", \"qna\", \"agency_gather_info\", \"gather_requirement\", \"recommend_product\", \"handover\", \"off_topic\", \"thank_you\"\nChỉ được chọn 1 trong 8 phase sau: \"greetings\", \"qna\", \"agency_gather_info\", \"gather_requirement\", \"recommend_product\", \"handover\", \"off_topic\", \"thank_you\"\n- \"greetings\" (Using for both Khách lẻ và Agency): chào hỏi, giới thiệu, đặt câu hỏi phân biệt khách lẻ hay cá nhân bán sỉ hay đại lý để hỗ trợ tốt hơn\n- \"qna\": (Using for both Khách lẻ và Agency) question and answer, dùng để trả lời các câu hỏi về doanh nghiệp, chính sách, địa chỉ, uy tín, liệu trình, phác đồ điều trị... Assistant ưu tiên chọn phase này cho Sales Staff nếu cần giải đáp câu hỏi của User. ASSISTANT MUST ALWAYS trả lời dựa trên thông tin xác thực. DO NOT ANSWER BASE ON SELF-CREATE INFORMATION. VERIFY THE INFORMATION CAREFULLY BEFORE RESPONDING. DO NOT chọn phase này khi Customer hỏi những câu hỏi liên quan đến sản phẩm because Sales Staff won't have information to answer.\n- \"agency_gather_info\": (Dùng cho Agency) Khi User là Agency hãy xếp vào phase này và đi theo quy trình khai thác thông tin đại lý: Hỏi thông tin + Giới thiệu chuyên sâu về sản phẩm mà Customer đang quan tâm/đề cập + Hỏi về vấn đề Customer đang gặp phải + Gửi các liệu trình liên quan. Đảm bảo đầy đủ các bước trước khi chuyển phase (trừ khi User chủ động yêu cầu chuyển phase). Khi hoàn tất khai thác thông tin agency, không cần xếp vào phase này nữa, hãy linh động dùng các phase khác như 1 khách hàng bình thường. Không đề xuất sản phẩm trong phase \"agency_gather_info\" khi User không yêu cầu về sản phẩm. Chỉ tập trung khai thác và đề xuất quy trình.\n- \"gather_requirement\": (Using for Khách lẻ) Khi User có nhu cầu nhưng chưa rõ tên sản phẩm cụ thể, hãy xếp vào phase này để khai thác thông tin làm rõ yêu cầu. Chỉ cần 1 đến 3 lượt hỏi để khai thác tình trạng/nhu cầu của User. Khi User tỏ ra mất kiên nhẫn, Assistant hãy ngay lập tức chuyển qua phase \"recommend_product\". Khi Customer mentions da bị nám, xỉn màu... Assistant MUST ALWAYS hỏi thêm để làm rõ lí do bị nám, xỉn màu...\n- \"recommend_product\": (Using for both Khách lẻ và Agency) Assistant MUST chọn phase này khi User cần cung cấp thông tin về sản phẩm cụ thể nào đó OR khi User đặt những câu hỏi liên quan đến sản phẩm mà {{company_name}} hỗ trợ OR khi User cần đề xuất thêm các sản phẩm khác OR khi User cần cung cấp thông tin về sản phẩm nào đó của 1 brand nào đó. Khi đã hoàn thành phase \"gather_requirement\", hãy chọn phase này để giới thiệu & tư vấn sản phẩm. Chủ động chia sẻ cụ thể về công dụng của sản phẩm, áp dụng vào tình huống cụ thể của User. Thuyết phục và cho User thấy đó là một sản phẩm cực kỳ phù hợp. ASSISTANT MUST ALWAYS cung cấp ĐẦY ĐỦ VÀ CHÍNH XÁC thông tin của sản phẩm. Assistant remember to choose this phase whenever User asks about products (ví dụ: \"H8 night skin serum là sản phẩm gì\" -> \"phase\": \"recommend_product\")\n- \"handover\": User là cá nhân bán sỉ OR User phẫn nộ, muốn nói chuyện với quản lý, User muốn nói chuyện với con người, Khách hàng nội bộ, là nhân viên công ty, tìm hàng cận date, giao hàng gấp, grab, check date sản phẩm, check chuyển khoản, hỏi những thông tin liên quan đến mẹ bầu, phụ nữ có thai, đang cho con bú... If xác định \"customer_class\" là \"personal\" THEN mặc định điều hướng \"phase\" sang \"handover\" do Assistant không hỗ trợ loại Customer này.\n- \"off_topic\" (Using for both Khách lẻ và Agency): những topic không liên quan, nói nhảm, viết code, làm thơ\n- \"thank_you\" (Using for both Khách lẻ và Agency): cảm ơn User, gửi link [https://shopee.vn/yduocvhn](https://shopee.vn/yduocvhn) khi User muốn đặt hàng, kết thúc cuộc trò chuyện.",
                    "## phase\nChỉ được chọn 1 trong 8 phase sau: \"greetings\", \"qna\", \"agency_gather_info\", \"gather_requirement\", \"recommend_product\", \"handover\", \"off_topic\", \"thank_you\"\n- \"greetings\": chào hỏi, giới thiệu, phân biệt khách hàng (Lẻ, Sỉ, Đại lý).\n- \"qna\": trả lời về công ty, chính sách, địa chỉ, liệu trình, phác đồ. KHÔNG chọn khi hỏi về sản phẩm. Chỉ trả lời dựa trên thông tin xác thực.\n- \"agency_gather_info\": (Dành cho Agency) khai thác thông tin đại lý theo quy trình (Hỏi thông tin -> Giới thiệu SP quan tâm -> Vấn đề gặp phải -> Liệu trình). Không đề xuất sản phẩm nếu không được yêu cầu.\n- \"gather_requirement\": (Dành cho Khách lẻ) khai thác thông tin khi chưa rõ tên SP (1-3 câu hỏi). Nếu User mất kiên nhẫn, lập tức chuyển phase \"recommend_product\". Nếu User bị nám/xỉn màu, phải hỏi rõ lý do.\n- \"recommend_product\": BẮT BUỘC CHỌN KHI User hỏi, yêu cầu, hoặc cần tư vấn về SẢN PHẨM cụ thể. Chủ động tư vấn công dụng phù hợp với User. Cung cấp ĐẦY ĐỦ, CHÍNH XÁC thông tin sản phẩm.\n- \"handover\": User là cá nhân bán sỉ, phẫn nộ, muốn gặp quản lý/người thật, NV công ty, check date, giao gấp, hỏi về phụ nữ có thai/cho con bú (nếu ko có info). Mặc định nếu customer_class là \"personal\".\n- \"off_topic\": topic ngoài lề, nói nhảm, viết code.\n- \"thank_you\": cảm ơn, gửi link shopee, chốt sale, kết thúc chat."
                )
                
                # 3. Compress note_for_sales and customer_class
                inst = inst.replace(
                    "Khi xác định \"customer_class\" của Customer là \"retail\", \"note_for_sales\" luôn luôn là \"none\".\n\nKhi đã xác định được \"customer_class\" của Customer là \"agency\", phân loại dựa trên câu nói của User:\n- \"spa\": IF câu nói của User có những thông tin về {{ spa_in4 }}\n- \"clinic\": IF câu nói của User có những thông tin về {{ phong_kham_in4 }}\n- \"aesthetic\": IF câu nói của User có những thông tin về {{ tham_my_vien_in4 }}\n- \"hospital\": IF câu nói của User có những thông tin về {{ benh_vien_in4 }}\n- \"pharmacy\": IF câu nói của User có những thông tin về {{ he_thong_nha_thuoc_in4 }}",
                    "Khi customer_class là \"retail\" -> \"note_for_sales\" = \"none\".\nKhi customer_class là \"agency\":\n- \"spa\": nếu có thông tin về {{ spa_in4 }}\n- \"clinic\": nếu có thông tin về {{ phong_kham_in4 }}\n- \"aesthetic\": nếu có thông tin về {{ tham_my_vien_in4 }}\n- \"hospital\": nếu có thông tin về {{ benh_vien_in4 }}\n- \"pharmacy\": nếu có thông tin về {{ he_thong_nha_thuoc_in4 }}"
                )
                
                # 4. Compress constraints
                inst = inst.replace(
                    "- **OUTPUT MUST ALWAYS BE IN VALID JSON FORMAT**.\n- NGHIÊM CẤM các trường hợp tự ý giảm giá cho User khi User yêu cầu.\n- Output JSON luôn luôn phải đầy đủ các biến sau: \"phase\", \"need_product_info\", \"customer_class\", \"current_step\", \"customer_name\", \"customer_phone\", \"user_context\", \"target_product\" và \"note_for_sales\".\n- Trong đó \"phase\":  Chỉ có thể là \"greetings\", \"qna\", \"agency_gather_info\", \"gather_requirement\", \"recommend_product\", \"handover\", \"off_topic\", \"thank_you\". NGHIÊM CẤM TẠO RA PHASE KHÁC. Khi tạo \"phase\" khác không thuộc các \"phase\" trên, chương trình sẽ bị lỗi. Vì vậy, hãy chọn trong các \"phase\" có sẵn. NGHIÊM CẤM TẠO PHASE MỚI. NGHIÊM CẤM VIÊT SAI TÊN PHASE.\n- IF Customer muốn đặt hàng THEN Assistant MUST ALWAYS chọn phase \"thank_you\" và gửi link [https://shopee.vn/yduocvhn](https://shopee.vn/yduocvhn) để Customer tự mình đặt hàng.\n- \"customer_class\":  Chỉ có thể là \"agency\", \"retail\" hoặc \"personal\". Khi chưa xác định được cụ thể, Assistant mặc định chọn `customer_class` là \"retail\"\n- \"need_product_info\": chỉ được là \"yes\" hoặc \"no\"\n- \"note_for_sales\": chỉ có thể là \"none\", \"spa\", \"clinic\", \"aesthetic\", \"hospital\", \"pharmacy\". \"note_for_sales\" mặc định ban đầu là \"none\". DO NOT tạo \"note_for_sales\" khác. NGHIÊM CẤM TẠO NOTE_FOR_SALES MỚI. NGHIÊM CẤM VIẾT SAI TÊN NOTE_FOR_SALES. DO NOT dùng từ đồng nghĩa.\n\nMANDATORY AND ALWAYS: WHEN THE USER USES ANY LANGUAGE, THE ASSISTANT MUST IMMEDIATELY RESPOND IN THE SAME LANGUAGE",
                    "# CONSTRAINTS\n- **OUTPUT MUST ALWAYS BE IN VALID JSON FORMAT**, ĐẦY ĐỦ CÁC BIẾN: \"phase\", \"need_product_info\", \"customer_class\", \"current_step\", \"customer_name\", \"customer_phone\", \"user_context\", \"target_product\", \"note_for_sales\".\n- NGHIÊM CẤM tự ý giảm giá.\n- \"phase\": CHỈ ĐƯỢC CHỌN TỪ: \"greetings\", \"qna\", \"agency_gather_info\", \"gather_requirement\", \"recommend_product\", \"handover\", \"off_topic\", \"thank_you\". NGHIÊM CẤM TẠO PHASE MỚI, KHÔNG VIẾT SAI TÊN.\n- \"customer_class\": \"agency\", \"retail\", hoặc \"personal\" (Mặc định: \"retail\").\n- \"need_product_info\": \"yes\" hoặc \"no\".\n- \"note_for_sales\": \"none\", \"spa\", \"clinic\", \"aesthetic\", \"hospital\", \"pharmacy\". NGHIÊM CẤM TẠO MỚI. DO NOT dùng từ đồng nghĩa.\n- Khi khách đặt hàng -> phase \"thank_you\" và gửi link Shopee.\n- MANDATORY: RESPOND IN USER'S LANGUAGE."
                )

                task['properties']['instruction'] = inst
                print(f"Compressed instruction from {original_len} to {len(inst)} characters.")
                break

with open('VHN_fixing.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=4)
